import { api, API_ENDPOINTS } from "./api";
import { Appointment, ApiResponse, PaginatedResponse, TimeSlot } from "@/types";

export interface CreateAppointmentData {
  doctor_id: number;
  date: string;
  time: string;
  type: "online" | "in_clinic";
  symptoms?: string;
  fee?: number;
}

export const appointmentService = {
  async getAppointments(
    filters?: { status?: string; date?: string },
    _page = 1,
    _limit = 10
  ): Promise<PaginatedResponse<Appointment>> {
    const params = new URLSearchParams();
    if (filters?.status) params.set("status", filters.status);
    if (filters?.date)   params.set("date",   filters.date);
    const query = params.toString() ? `?${params}` : "";
    const data = await api.get<Appointment[]>(`${API_ENDPOINTS.APPOINTMENTS}${query}`);
    return { data, success: true, page: 1, limit: data.length, total: data.length, totalPages: 1 };
  },

  async getAppointmentById(id: string): Promise<ApiResponse<Appointment>> {
    const data = await api.get<Appointment>(API_ENDPOINTS.APPOINTMENT_DETAIL(id));
    return { data, success: true };
  },

  async createAppointment(data: CreateAppointmentData): Promise<ApiResponse<Appointment>> {
    const result = await api.post<Appointment>(API_ENDPOINTS.APPOINTMENTS, data);
    return { data: result, success: true, message: "Appointment booked successfully" };
  },

  async updateAppointmentStatus(id: string, status: string, notes?: string): Promise<ApiResponse<Appointment>> {
    const result = await api.patch<Appointment>(API_ENDPOINTS.APPOINTMENT_DETAIL(id), { status, notes });
    return { data: result, success: true };
  },

  async cancelAppointment(id: string): Promise<ApiResponse<Appointment>> {
    return this.updateAppointmentStatus(id, "cancelled");
  },

  async getAvailableSlots(doctorId: string, date: string): Promise<ApiResponse<TimeSlot[]>> {
    const res = await api.get<{ date: string; slots: { time: string; is_available: boolean }[] }>(
      `${API_ENDPOINTS.APPOINTMENT_SLOTS(doctorId)}?date=${date}`
    );
    const slots: TimeSlot[] = res.slots.map((s, i) => ({
      id: `slot-${date}-${s.time}`,
      date,
      startTime: s.time,
      endTime: s.time,
      isAvailable: s.is_available,
    }));
    return { data: slots, success: true };
  },

  async getTodayQueue(): Promise<ApiResponse<Appointment[]>> {
    const data = await api.get<Appointment[]>(API_ENDPOINTS.TODAY_QUEUE);
    return { data, success: true };
  },
};
