import { api, API_ENDPOINTS } from "./api";
import { Conversation, Message, ApiResponse } from "@/types";

export const chatService = {
  async getConversations(_userId: string): Promise<ApiResponse<Conversation[]>> {
    const data = await api.get<Conversation[]>(API_ENDPOINTS.CONVERSATIONS);
    return { data, success: true };
  },

  async getConversationById(conversationId: string): Promise<ApiResponse<Conversation>> {
    // conversations are fetched as a list; find by id
    const all = await api.get<Conversation[]>(API_ENDPOINTS.CONVERSATIONS);
    const conv = all.find((c) => String(c.id) === String(conversationId));
    if (!conv) throw new Error("Conversation not found");
    return { data: conv, success: true };
  },

  async getMessages(conversationId: string): Promise<ApiResponse<Message[]>> {
    const data = await api.get<Message[]>(API_ENDPOINTS.MESSAGES(conversationId));
    return { data, success: true };
  },

  async sendMessage(
    conversationId: string,
    _senderId: string,
    _senderRole: string,
    content: string,
    type: "text" | "image" | "file" | "prescription" = "text",
    file?: File
  ): Promise<ApiResponse<Message>> {
    let result: Message;
    if (file) {
      const form = new FormData();
      form.append("content", content);
      form.append("type", type);
      form.append("file", file);
      result = await api.upload<Message>(API_ENDPOINTS.MESSAGES(conversationId), form);
    } else {
      result = await api.post<Message>(API_ENDPOINTS.MESSAGES(conversationId), { content, type });
    }
    return { data: result, success: true, message: "Message sent" };
  },

  async createConversation(
    _patientId: string,
    doctorId: string
  ): Promise<ApiResponse<Conversation>> {
    const data = await api.post<Conversation>(API_ENDPOINTS.CONVERSATIONS, { doctor_id: Number(doctorId) });
    return { data, success: true };
  },

  async markAsRead(_conversationId: string, _userId: string): Promise<ApiResponse<void>> {
    // reading messages automatically marks them as read on the backend
    return { data: undefined, success: true };
  },

  async getUnreadCount(_userId: string): Promise<ApiResponse<number>> {
    const all = await api.get<Conversation[]>(API_ENDPOINTS.CONVERSATIONS);
    const count = all.reduce((sum, c) => sum + ((c as any).unread_count ?? 0), 0);
    return { data: count, success: true };
  },
};
